namespace BgControls.Windows.Controls;/// <summary>/// 定义选项卡项（TabItem）的通用接口./// 该接口规定了自定义选项卡控件与其项容器之间交互所需的核心属性和方法./// </summary>public interface ITabItem{    /// <summary>    /// Gets or sets a value indicating whether 当前选项卡项是否已被选中.    /// </summary>    /// <value>    /// 如果已选中，则为 <see langword="true"/>；否则为 <see langword="false"/>.    /// </value>    bool IsSelected { get; set; }    /// <summary>    /// Gets 与此选项卡项关联的底层控件实例.    /// </summary>    Control Control { get; }    /// <summary>    /// Gets 当前选项卡栏（TabStrip）在选项卡控件中的停靠位置.    /// </summary>    /// <value>    /// 停靠位置，通常为顶部、底部、左侧或右侧.    /// </value>    Dock TabStripPlacement { get; }    /// <summary>    /// 更新选项卡栏的停靠位置，并触发相关的布局调整.    /// </summary>    /// <param name="placement">新的停靠位置.</param>    void UpdateTabStripPlacement(Dock placement);    /// <summary>    /// 设置选项卡的内容排列方向.    /// </summary>    /// <param name="orientation">排列方向（水平或垂直）.</param>    void SetTabOrientation(Orientation orientation);    /// <summary>    /// 强制更新标头呈现器（Header Presenter）的内容，用于同步视觉显示.    /// </summary>    void UpdateHeaderPresenterContent();}